script:
// Employee Advances Report
// Loads data from SQL query using Frappe database

(function(root_element) {
    'use strict';

    // Use root_element if provided (for Custom HTML blocks), otherwise use document
    const root = root_element || document;

    // Helper to find elements (using getEl to avoid conflict with jQuery $)
    function getEl(id) {
        if (typeof id === 'string' && id.startsWith('#')) {
            const elementId = id.substring(1);
            let el = root.getElementById ? root.getElementById(elementId) : null;
            if (!el && root.querySelector) el = root.querySelector(id);
            if (!el) el = document.getElementById(elementId);
            return el;
        }
        if (root && root.querySelector) return root.querySelector(id);
        return document.querySelector(id);
    }

    // Format currency (matching ledger style)
    function formatCurrency(amount) {
        const num = parseFloat(amount) || 0;
        return num.toLocaleString(undefined, { 
            minimumFractionDigits: 0, 
            maximumFractionDigits: 0 
        });
    }

    // Show error
    function showError(message) {
        const errorEl = getEl('#error-message');
        if (errorEl) {
            errorEl.textContent = message;
            errorEl.style.display = 'block';
        }
        console.error('Error:', message);
    }

    // Hide error
    function hideError() {
        const errorEl = getEl('#error-message');
        if (errorEl) {
            errorEl.style.display = 'none';
        }
    }

    // Show loading
    function showLoading() {
        const loadingEl = getEl('#loading');
        if (loadingEl) {
            loadingEl.style.display = 'block';
        }
    }

    // Hide loading
    function hideLoading() {
        const loadingEl = getEl('#loading');
        if (loadingEl) {
            loadingEl.style.display = 'none';
        }
    }

    // Render table with month-wise columns
    function renderTable(data, months) {
        const tbody = getEl('#table-body');
        const thead = getEl('#table-head');
        
        // Retry if elements not found (DOM might not be ready)
        if (!tbody || !thead) {
            console.warn('Table body or head element not found, retrying...');
            setTimeout(function() {
                renderTable(data, months);
            }, 200);
            return;
        }
        
        const numCols = 6 + (months ? months.length : 0);
        
        if (!data || data.length === 0) {
            tbody.innerHTML = `<tr><td colspan="${numCols}" class="no-data">No employee advances found</td></tr>`;
            return;
        }

        // Build month header columns
        const monthHeaders = months ? months.map(month => 
            `<th class="month-header" style="background:linear-gradient(135deg, #667eea 0%, #764ba2 100%) !important;color:#fff !important;font-weight:800 !important;padding:14px 16px;text-align:right;">${month.name}</th>`
        ).join('') : '';

        // Update table header - insert month columns before closing balance
        const headerRow = thead.querySelector('tr');
        if (headerRow) {
            // Remove ALL existing month headers first (more thorough cleanup)
            const allHeaders = headerRow.querySelectorAll('th');
            allHeaders.forEach((th, idx) => {
                // Remove any th that is between opening balance (index 4) and closing balance (last)
                if (idx > 4 && idx < allHeaders.length - 1) {
                    th.remove();
                }
            });
            
            // Now insert new month headers before closing balance
            if (monthHeaders) {
                const closingBalanceTh = headerRow.querySelector('th:last-child');
                if (closingBalanceTh) {
                    // Insert month headers before closing balance
                    closingBalanceTh.insertAdjacentHTML('beforebegin', monthHeaders);
                }
            }
        }

        // Calculate totals
        const totalOpening = data.reduce((sum, row) => sum + (parseFloat(row.opening_balance) || 0), 0);
        const totalClosing = data.reduce((sum, row) => sum + (parseFloat(row.closing_balance) || 0), 0);
        const monthTotals = {};
        if (months) {
            months.forEach(month => {
                monthTotals[month.key] = data.reduce((sum, row) => {
                    return sum + (parseFloat(row.month_transactions && row.month_transactions[month.key]) || 0);
                }, 0);
            });
        }
        
        // Build table rows
        tbody.innerHTML = data.map((row, index) => {
            const closingBalance = parseFloat(row.closing_balance) || 0;
            const openingBalance = parseFloat(row.opening_balance) || 0;
            const balanceClass = closingBalance > 0 ? 'positive' : closingBalance < 0 ? 'negative' : '';
            const isNegative = closingBalance < 0;
            const rowBg = isNegative ? 'background:#fee2e2;' : '';
            const hoverBg = isNegative ? '#fecaca' : '#f8fafc';
            
            // Build month transaction cells
            const monthCells = months ? months.map(month => {
                const monthAmount = parseFloat(row.month_transactions && row.month_transactions[month.key]) || 0;
                const monthClass = monthAmount > 0 ? 'positive' : monthAmount < 0 ? 'negative' : '';
                return `<td class="month-cell" style="text-align:right;font-weight:700;color:#334155;font-family:monospace;"><span class="balance ${monthClass}">${formatCurrency(monthAmount)}</span></td>`;
            }).join('') : '';
            
            return `
                <tr style="border-bottom:1px solid #e5e7eb;transition:background 0.2s;${rowBg}" onmouseover="this.style.background='${hoverBg}'" onmouseout="this.style.background='${isNegative ? '#fee2e2' : ''}'">
                    <td style="font-weight:600;color:#334155;font-family:monospace;">${index + 1}</td>
                    <td class="employee-name">${escapeHtml(row.employee_name || 'N/A')}</td>
                    <td><span class="badge">${escapeHtml(row.employee || 'N/A')}</span></td>
                    <td style="color:#64748b;">${escapeHtml(row.branch || 'N/A')}</td>
                    <td style="text-align:right;font-weight:700;color:#334155;font-family:monospace;"><span class="balance ${openingBalance >= 0 ? 'positive' : 'negative'}">${formatCurrency(openingBalance)}</span></td>
                    ${monthCells}
                    <td style="text-align:right;font-weight:700;color:#334155;font-family:monospace;"><span class="balance ${balanceClass}">${formatCurrency(closingBalance)}</span></td>
                </tr>
            `;
        }).join('') + `
            <tr style="background:linear-gradient(135deg, #f7f2ff 0%, #e9d5ff 100%);font-weight:800;border-top:2px solid #667eea;">
                <td colspan="4" style="text-align:right;padding:16px 12px;color:#5b2db3;">TOTAL:</td>
                <td style="text-align:right;padding:16px 12px;font-size:15px;color:#5b2db3;">
                    <span class="balance ${totalOpening >= 0 ? 'positive' : 'negative'}">${formatCurrency(totalOpening)}</span>
                </td>
                ${months ? months.map(month => {
                    const monthTotal = monthTotals[month.key] || 0;
                    return `<td style="text-align:right;padding:16px 12px;font-size:15px;color:#5b2db3;"><span class="balance ${monthTotal >= 0 ? 'positive' : 'negative'}">${formatCurrency(monthTotal)}</span></td>`;
                }).join('') : ''}
                <td style="text-align:right;padding:16px 12px;font-size:15px;color:#5b2db3;">
                    <span class="balance ${totalClosing >= 0 ? 'positive' : 'negative'}">${formatCurrency(totalClosing)}</span>
                </td>
            </tr>
        `;
    }

    // Format number with commas
    function formatNumber(n) {
        return Number(n || 0).toLocaleString();
    }

    // Calculate and render stats as KPI cards (like hr attendance)
    function renderStats(data) {
        const statsContainer = getEl('#stats');
        if (!statsContainer) {
            console.error('Stats container not found');
            return;
        }

        if (!data || data.length === 0) {
            statsContainer.innerHTML = '';
            return;
        }

        const total = data.length;
        const balance = data.reduce((sum, row) => sum + (parseFloat(row.closing_balance) || 0), 0);
        const positive = data.filter(row => (parseFloat(row.closing_balance) || 0) > 0).length;
        const negative = data.filter(row => (parseFloat(row.closing_balance) || 0) < 0).length;

        // Calculate positive and negative totals
        const positiveTotal = data
            .filter(row => (parseFloat(row.closing_balance) || 0) > 0)
            .reduce((sum, row) => sum + (parseFloat(row.closing_balance) || 0), 0);
        
        const negativeTotal = data
            .filter(row => (parseFloat(row.closing_balance) || 0) < 0)
            .reduce((sum, row) => sum + (parseFloat(row.closing_balance) || 0), 0);

        // Calculate branch-wise totals
        const branchTotals = {};
        data.forEach(row => {
            const branch = row.branch || 'No Branch';
            if (!branchTotals[branch]) {
                branchTotals[branch] = 0;
            }
            branchTotals[branch] += parseFloat(row.closing_balance) || 0;
        });

        const branchList = Object.entries(branchTotals)
            .sort((a, b) => Math.abs(b[1]) - Math.abs(a[1]))
            .slice(0, 5); // Top 5 branches

        const kpiCards = [
            {
                title: "Total Employees",
                value: formatNumber(total),
                icon: "👥",
                color: "linear-gradient(135deg, #6366f1 0%, #2563eb 100%)",
                bg: "rgba(99, 102, 241, 0.1)",
                isSmall: true
            },
            {
                title: "Total Balance",
                value: formatCurrency(balance),
                icon: balance >= 0 ? "💰" : "💸",
                color: balance >= 0 
                    ? "linear-gradient(135deg, #22c55e 0%, #16a34a 100%)"
                    : "linear-gradient(135deg, #ef4444 0%, #dc2626 100%)",
                bg: balance >= 0 
                    ? "rgba(34, 197, 94, 0.1)"
                    : "rgba(239, 68, 68, 0.1)",
                isSmall: true
            },
            {
                title: "Positive Balances",
                value: formatCurrency(positiveTotal),
                icon: "✅",
                color: "linear-gradient(135deg, #22c55e 0%, #16a34a 100%)",
                bg: "rgba(34, 197, 94, 0.1)",
                isSmall: true
            },
            {
                title: "Negative Balances",
                value: formatCurrency(Math.abs(negativeTotal)),
                icon: "⚠️",
                color: "linear-gradient(135deg, #ef4444 0%, #dc2626 100%)",
                bg: "rgba(239, 68, 68, 0.1)",
                isSmall: true
            }
        ];

        // Add branch-wise indicators
        branchList.forEach(([branch, total], index) => {
            if (index < 5) { // Limit to 5 branches
                kpiCards.push({
                    title: branch,
                    value: formatCurrency(total),
                    icon: "🏢",
                    color: total >= 0 
                        ? "linear-gradient(135deg, #8b5cf6 0%, #6d28d9 100%)"
                        : "linear-gradient(135deg, #f59e0b 0%, #f97316 100%)",
                    bg: total >= 0 
                        ? "rgba(139, 92, 246, 0.1)"
                        : "rgba(245, 158, 11, 0.1)",
                    isSmall: true
                });
            }
        });

        statsContainer.innerHTML = kpiCards.map(kpi => {
            const isSmall = true; // All small
            const padding = "11.5px"; // 15% increase from 10px
            const iconSize = "21px"; // 15% increase from 18px
            const valueSize = "18px"; // 15% increase from 16px
            const titleSize = "10px"; // 15% increase from 9px
            const minWidth = "161px"; // 15% increase from 140px
            
            return `
                <div style="background:#fff;border-radius:10px;padding:${padding};box-shadow:0 2px 8px rgba(0,0,0,0.08);border-left:4px solid;border-image:${kpi.color} 1;transition:transform 0.2s,box-shadow 0.2s;cursor:pointer;flex:0 0 auto;min-width:${minWidth};white-space:nowrap;" onmouseover="this.style.transform='translateY(-4px)';this.style.boxShadow='0 8px 16px rgba(0,0,0,0.15)'" onmouseout="this.style.transform='';this.style.boxShadow='0 2px 8px rgba(0,0,0,0.08)'">
                    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;">
                        <div style="font-size:${iconSize};">${kpi.icon}</div>
                        <div style="background:${kpi.bg};padding:4px 8px;border-radius:6px;font-size:${titleSize};font-weight:700;color:#334155;text-transform:uppercase;letter-spacing:0.3px;white-space:nowrap;">${kpi.title}</div>
                    </div>
                    <div style="font-size:${valueSize};font-weight:900;background:${kpi.color};-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1.2;white-space:nowrap;">${kpi.value}</div>
                    ${kpi.mini ? `<div style="margin-top:6px;font-size:9px;color:#64748b;font-weight:600;">${kpi.mini}</div>` : ''}
                </div>
            `;
        }).join('');

        // Update total balance display
    }

    // Escape HTML to prevent XSS
    function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    // Get filter values
    function getFilters() {
        const fromDateEl = getEl('#filter-from-date');
        const toDateEl = getEl('#filter-to-date');
        const accountEl = getEl('#filter-account');
        const companyEl = getEl('#filter-company');
        const branchEl = getEl('#filter-branch');
        const departmentEl = getEl('#filter-department');
        return {
            from_date: fromDateEl ? fromDateEl.value : null,
            to_date: toDateEl ? toDateEl.value : null,
            account: accountEl ? accountEl.value : 'Employee Advances - TCPL',
            company: companyEl ? companyEl.value : null,
            branch: branchEl ? branchEl.value : null,
            department: departmentEl ? departmentEl.value : null
        };
    }

    // Load branches into dropdown
    function loadBranches() {
        if (typeof frappe === 'undefined') return;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Branch',
                fields: ['name'],
                limit_page_length: 1000
            },
            callback: function(r) {
                const branchEl = getEl('#filter-branch');
                if (!branchEl) return;

                const branches = r.message || [];
                branches.forEach(branch => {
                    const option = document.createElement('option');
                    option.value = branch.name;
                    option.textContent = branch.name;
                    branchEl.appendChild(option);
                });
            },
            error: function(err) {
                console.error('Error loading branches:', err);
            }
        });
    }

    // Load departments into dropdown
    function loadDepartments() {
        if (typeof frappe === 'undefined') return;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Department',
                fields: ['name'],
                limit_page_length: 1000
            },
            callback: function(r) {
                const departmentEl = getEl('#filter-department');
                if (!departmentEl) return;

                const departments = r.message || [];
                departments.forEach(dept => {
                    const option = document.createElement('option');
                    option.value = dept.name;
                    option.textContent = dept.name;
                    departmentEl.appendChild(option);
                });
            },
            error: function(err) {
                console.error('Error loading departments:', err);
            }
        });
    }

    // Load companies into dropdown
    function loadCompanies() {
        if (typeof frappe === 'undefined') return;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Company',
                fields: ['name'],
                limit_page_length: 1000
            },
            callback: function(r) {
                const companyEl = getEl('#filter-company');
                if (!companyEl) return;

                const companies = r.message || [];
                companies.forEach(company => {
                    const option = document.createElement('option');
                    option.value = company.name;
                    option.textContent = company.name;
                    companyEl.appendChild(option);
                });
            },
            error: function(err) {
                console.error('Error loading companies:', err);
            }
        });
    }

    // Set default dates (from date: first day of current month, to date: today)
    function setDefaultDates() {
        const today = new Date();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        
        const fromDateEl = getEl('#filter-from-date');
        const toDateEl = getEl('#filter-to-date');
        
        if (fromDateEl && !fromDateEl.value) {
            // First day of current month
            fromDateEl.value = `${year}-${month}-01`;
        }
        
        if (toDateEl && !toDateEl.value) {
            // Today
            toDateEl.value = `${year}-${month}-${day}`;
        }
    }

    // Get month name from date string (YYYY-MM-DD)
    function getMonthName(dateStr) {
        if (!dateStr) return '';
        const date = new Date(dateStr + 'T00:00:00');
        const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
        return monthNames[date.getMonth()];
    }

    // Get all months between from_date and to_date (starting from from_date month)
    function getMonthsBetween(fromDate, toDate) {
        const months = [];
        if (!fromDate || !toDate) return months;
        
        const start = new Date(fromDate + 'T00:00:00');
        const end = new Date(toDate + 'T00:00:00');
        
        // Start from the month of from_date (not before)
        // Use the exact month and year of from_date
        const fromYear = start.getFullYear();
        const fromMonth = start.getMonth(); // 0-indexed (0=Jan, 7=Aug)
        const toYear = end.getFullYear();
        const toMonth = end.getMonth();
        
        let currentYear = fromYear;
        let currentMonth = fromMonth;
        
        while (currentYear < toYear || (currentYear === toYear && currentMonth <= toMonth)) {
            const monthKey = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}`; // YYYY-MM
            const monthName = getMonthName(`${monthKey}-01`);
            months.push({ key: monthKey, name: monthName });
            
            // Move to next month
            currentMonth++;
            if (currentMonth > 11) {
                currentMonth = 0;
                currentYear++;
            }
        }
        
        return months;
    }

    // Load data from SQL query
    function loadData() {
        const filters = getFilters();
        const account = filters.account || 'Employee Advances - TCPL';
        const company = filters.company || null;
        const branch = filters.branch || null;
        const department = filters.department || null;
        const fromDate = filters.from_date || frappe.datetime.get_today();
        const toDate = filters.to_date || frappe.datetime.get_today();
        
        if (!fromDate || !toDate) {
            showError('Please select From Date and To Date');
            return;
        }
        
        hideError();
        showLoading();
        
        const tbody = getEl('#table-body');
        if (!tbody) {
            console.error('Table body element not found. Waiting for DOM...');
            setTimeout(function() {
                loadData();
            }, 500);
            return;
        }
        
        // Get months between from_date and to_date
        const months = getMonthsBetween(fromDate, toDate);
        
        // Calculate number of columns dynamically
        const initialCols = 6; // #, Employee Name, Employee ID, Branch, Opening Balance, Closing Balance
        const monthCols = months ? months.length : 0;
        const totalCols = initialCols + monthCols;
        tbody.innerHTML = `<tr><td colspan="${totalCols}" class="loading">Loading data...</td></tr>`;

        // Check if Frappe is available
        if (typeof frappe === 'undefined') {
            showError('Frappe framework not available. Please run this in a Frappe/ERPNext environment.');
            return;
        }

        // Store filters in variables accessible to nested callbacks
        const accountFilter = account;
        const companyFilter = company;
        const branchFilter = branch;
        const departmentFilter = department;
        const fromDateFilter = fromDate;
        const toDateFilter = toDate;

        // Client-side data fetching using frappe.client APIs
        // Step 1: Get selected account (default: Employee Advances - TCPL)
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Account',
                name: accountFilter
            },
            callback: function(accR) {
                if (!accR.message) {
                    showError(accountFilter + ' account not found');
                    renderStats([]);
                    renderTable([], []);
                    hideLoading();
                    return;
                }

                const account = accR.message;
                
                // Step 2: Get all accounts in the hierarchy
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Account',
                        fields: ['name'],
                        filters: [
                            ['lft', '>=', account.lft],
                            ['rgt', '<=', account.rgt]
                        ],
                        limit_page_length: 10000
                    },
                    callback: function(accListR) {
                        const accountNames = (accListR.message || []).map(a => a.name);
                        
                        if (accountNames.length === 0) {
                            showError('No accounts found under ' + accountFilter);
                            renderStats([]);
                            renderTable([], []);
                            hideLoading();
                            return;
                        }

                        // Step 3: Get all GL Entries up to to_date (we'll filter by date ranges later)
                        const glFilters = [
                            ['docstatus', '=', 1],
                            ['party_type', '=', 'Employee'],
                            ['is_cancelled', '=', 0],
                            ['posting_date', '<=', toDate],
                            ['account', 'in', accountNames]
                        ];

                        // Add company filter if selected
                        if (companyFilter) {
                            glFilters.push(['company', '=', companyFilter]);
                        }

                        // Add branch filter if selected
                        if (branch) {
                            // We'll filter by branch after getting employees
                        }

                        frappe.call({
                            method: 'frappe.client.get_list',
                            args: {
                                doctype: 'GL Entry',
                                fields: ['party', 'debit', 'credit', 'account', 'posting_date'],
                                filters: glFilters,
                                limit_page_length: 10000
                            },
                            callback: function(glR) {
                                const glEntries = glR.message || [];
                                
                                // Step 4: Get all employees
                                frappe.call({
                                    method: 'frappe.client.get_list',
                                    args: {
                                        doctype: 'Employee',
                                        fields: ['name', 'employee_name', 'branch', 'department'],
                                        limit_page_length: 10000
                                    },
                                    callback: function(empR) {
                                        // Build employee lookup
                                        const employees = {};
                                        (empR.message || []).forEach(emp => {
                                            employees[emp.name] = {
                                                employee_name: emp.employee_name || emp.name,
                                                branch: emp.branch || '',
                                                department: emp.department || ''
                                            };
                                        });

                                        // Process GL entries and calculate opening balance, month-wise transactions, and closing balance
                                        const employeeBalances = {};
                                        
                                        glEntries.forEach(entry => {
                                            const empId = entry.party;
                                            const emp = employees[empId];
                                            
                                            // Apply branch filter if provided
                                            if (branchFilter && (!emp || emp.branch !== branchFilter)) {
                                                return;
                                            }
                                            
                                            // Apply department filter if provided
                                            if (departmentFilter && (!emp || emp.department !== departmentFilter)) {
                                                return;
                                            }
                                            
                                            if (!employeeBalances[empId]) {
                                                employeeBalances[empId] = {
                                                    employee_name: (emp && emp.employee_name) || empId,
                                                    employee: empId,
                                                    branch: (emp && emp.branch) || '',
                                                    opening_balance: 0,
                                                    closing_balance: 0,
                                                    month_transactions: {}
                                                };
                                                // Initialize month transactions
                                                months.forEach(month => {
                                                    employeeBalances[empId].month_transactions[month.key] = 0;
                                                });
                                            }
                                            
                                            const entryDate = entry.posting_date;
                                            const entryAmount = (parseFloat(entry.debit) || 0) - (parseFloat(entry.credit) || 0);
                                            
                                            // Calculate opening balance (before from_date)
                                            if (entryDate < fromDate) {
                                                employeeBalances[empId].opening_balance += entryAmount;
                                            }
                                            
                                            // Calculate month-wise transactions (between from_date and to_date)
                                            // Only include transactions from the from_date month onwards
                                            if (entryDate >= fromDate && entryDate <= toDate) {
                                                const entryMonth = entryDate.slice(0, 7); // YYYY-MM
                                                // Only add if this month is in our months array (from from_date onwards)
                                                const monthExists = months.some(m => m.key === entryMonth);
                                                if (monthExists && employeeBalances[empId].month_transactions[entryMonth] !== undefined) {
                                                    employeeBalances[empId].month_transactions[entryMonth] += entryAmount;
                                                }
                                            }
                                            
                                            // Calculate closing balance (up to to_date)
                                            if (entryDate <= toDate) {
                                                employeeBalances[empId].closing_balance += entryAmount;
                                            }
                                        });
                                        
                                        // Convert to array, filter non-zero, remove invalid entries, and sort
                                        const data = Object.values(employeeBalances)
                                            .filter(emp => {
                                                // Filter out entries with missing employee data
                                                const hasValidEmployee = emp.employee_name && 
                                                                         emp.employee_name !== 'N/A' && 
                                                                         emp.employee_name !== emp.employee &&
                                                                         emp.employee !== 'N/A';
                                                const hasNonZeroBalance = Math.abs(emp.closing_balance) > 0.01;
                                                return hasValidEmployee && hasNonZeroBalance;
                                            })
                                            .sort((a, b) => (a.employee_name || '').localeCompare(b.employee_name || ''));
                                        
                                        renderStats(data);
                                        renderTable(data, months);
                                        hideLoading();
